// TradeK OS — gera PDF de Proforma Invoice no padrão comercial TradeK.
import { PDFDocument, rgb, StandardFonts, PDFPage, PDFFont } from "npm:pdf-lib@1.17.1"
import { decodeBase64 } from "jsr:@std/encoding@1/base64"

const LIME    = rgb(0.216, 0.255, 0.318)  // cinza chumbo #374151
const BG      = rgb(1.0,   1.0,   1.0  )
const BG_2    = rgb(0.13,  0.16,  0.12 )
const BG_3    = rgb(0.95,  0.97,  0.93 )
const LINE    = rgb(0.80,  0.82,  0.78 )
const TX      = rgb(0.10,  0.12,  0.09 )
const TX_DIM  = rgb(0.35,  0.38,  0.32 )
const TX_INV  = rgb(0.93,  0.95,  0.92 )  // texto claro p/ fundo escuro (header)

const PW = 595.28
const PH = 841.89
const MX = 40
const FOOTER_Y = 38

const ALIC_LOGO_PNG_B64 = ""

export type ProposalFicha = {
  motor: string | null; velocidade: string | null; autonomia: string | null
  bateria: string | null; freios: string | null; capacidade: string | null; moq: string | null
  hsCode: string | null
}
export type ProposalItemData = {
  produto: string; categoria: string | null; ficha: ProposalFicha
  quantidade: number | null; valorUnit: number | null; imagemUrl: string | null
  coresEscolhidas?: string[]
  observacoes?: string | null
}
export type ProposalPdfData = {
  proposalId: string; empresa: string; cnpj: string; contato: string
  itens: ProposalItemData[]; valor: number | null; moeda: string
  observacoes: string | null; criadaEm: string
  portoOrigem?: string; portoDestino?: string; dataEntrega?: string
}

export async function buildProposalPdf(d: ProposalPdfData): Promise<Uint8Array> {
  const doc = await PDFDocument.create()
  const font = await doc.embedFont(StandardFonts.Helvetica)
  const bold = await doc.embedFont(StandardFonts.HelveticaBold)

  let page = doc.addPage([PW, PH])
  fill(page, 0, 0, PW, PH, BG)

  // logo TradeK
  let tradekLogo: Awaited<ReturnType<typeof doc.embedPng>> | null = null
  try {
    const r = await fetch("https://www.tradek.com.br/tradek-logo.png")
    tradekLogo = await doc.embedPng(new Uint8Array(await r.arrayBuffer()))
  } catch { /* logo opcional */ }

  // logo ALIC (embutido como base64)
  let alicLogo: Awaited<ReturnType<typeof doc.embedPng>> | null = null
  try {
    alicLogo = await doc.embedPng(decodeBase64(ALIC_LOGO_PNG_B64))
  } catch (e) { console.warn("ALIC logo embed error:", e) }

  // ── HEADER ───────────────────────────────────────────────────────────────
  // Ambos os logos preenchem a mesma largura de zona (120px), altura proporcional
  const ZONE_W  = 95
  const headerH = 100
  fill(page, 0, PH - headerH, PW, headerH, BG_2)
  fill(page, 0, PH - headerH - 3, PW, 3, LIME)

  // Título centralizado no topo do header
  const title1 = "PROFORMA INVOICE"
  const title2 = "COTAÇÃO COMERCIAL"
  const t1w = bold.widthOfTextAtSize(title1, 14)
  const t2w = bold.widthOfTextAtSize(title2, 7)
  const cx = PW / 2
  txt(page, bold, title2, cx - t2w / 2, PH - 16, 7, TX_INV)
  txt(page, bold, title1, cx - t1w / 2, PH - 32, 14, TX_INV)

  // Logos centralizados verticalmente no espaço abaixo do título
  // Área de logo: de PH-48 (abaixo do título) até PH-headerH (base do header)
  const LOGO_AREA_TOP    = PH - 48
  const LOGO_AREA_BOTTOM = PH - headerH + 8
  const LOGO_CENTER_Y    = (LOGO_AREA_TOP + LOGO_AREA_BOTTOM) / 2  // centro vertical

  function logoCentered(imgW: number, imgH: number) {
    const lw = ZONE_W
    const lh = (imgH / imgW) * lw
    return { lw, lh, ly: LOGO_CENTER_Y - lh / 2 }
  }

  // TradeK logo — esquerda, centrado verticalmente
  if (tradekLogo) {
    const { lw, lh, ly } = logoCentered(tradekLogo.width, tradekLogo.height)
    page.drawImage(tradekLogo, { x: MX, y: ly, width: lw, height: lh })
  }

  // ALIC logo — direita, mesmo centro vertical que TradeK
  if (alicLogo) {
    const { lw, lh, ly } = logoCentered(alicLogo.width, alicLogo.height)
    page.drawImage(alicLogo, { x: PW - MX - lw, y: ly, width: lw, height: lh })
  }

  let y = PH - headerH - 18

  // Cria nova página com header idêntico ao da primeira folha
  function ensure(doc: PDFDocument, page: PDFPage, curY: number, needed: number): { page: PDFPage; y: number } {
    if (curY - needed > FOOTER_Y + 20) return { page, y: curY }
    drawFooter(page, font, PW)
    const np = doc.addPage([PW, PH])
    fill(np, 0, 0, PW, PH, BG)
    fill(np, 0, PH - headerH, PW, headerH, BG_2)
    fill(np, 0, PH - headerH - 3, PW, 3, LIME)
    const _t1w = bold.widthOfTextAtSize("PROFORMA INVOICE", 14)
    const _t2w = bold.widthOfTextAtSize("COTAÇÃO COMERCIAL", 7)
    const _cx = PW / 2
    txt(np, bold, "COTAÇÃO COMERCIAL", _cx - _t2w / 2, PH - 16, 7, TX_INV)
    txt(np, bold, "PROFORMA INVOICE",  _cx - _t1w / 2, PH - 32, 14, TX_INV)
    const _laTop = PH - 48
    const _laBot = PH - headerH + 8
    const _lcY   = (_laTop + _laBot) / 2
    function _lc(imgW: number, imgH: number) { const lw = ZONE_W; const lh = (imgH / imgW) * lw; return { lw, lh, ly: _lcY - lh / 2 } }
    if (tradekLogo) { const { lw, lh, ly } = _lc(tradekLogo.width, tradekLogo.height); np.drawImage(tradekLogo, { x: MX, y: ly, width: lw, height: lh }) }
    if (alicLogo)   { const { lw, lh, ly } = _lc(alicLogo.width,   alicLogo.height);   np.drawImage(alicLogo,   { x: PW - MX - lw, y: ly, width: lw, height: lh }) }
    return { page: np, y: PH - headerH - 18 }
  }

  // ── INFO: COMPRADOR + DADOS DA INVOICE ───────────────────────────────────
  const invoiceNum = `TK-${d.proposalId.slice(0, 4).toUpperCase()}/${new Date(d.criadaEm).getFullYear()}`
  const halfW = (PW - MX * 2 - 12) / 2
  const colR  = MX + halfW + 12

  // caixa comprador (esquerda) — altura fixa de 100px
  const infoH = 100
  fill(page, MX, y - infoH, halfW, infoH, BG_3)
  border(page, MX, y - infoH, halfW, infoH)
  txt(page, bold, "IMPORTER / COMPRADOR", MX + 10, y - 15, 7, LIME)
  txtClip(page, bold, d.empresa || "—", MX + 10, y - 29, 10.5, TX, halfW - 20)
  if (d.cnpj)    txt(page, font, `CNPJ/CPF: ${d.cnpj}`,      MX + 10, y - 44, 8, TX_DIM)
  if (d.contato) txt(page, font, `Contato: ${d.contato}`,     MX + 10, y - 58, 8, TX_DIM)

  // caixa dados da invoice (direita) — 3 linhas × 30px + 18px topo + 10px base = 100px
  fill(page, colR, y - infoH, halfW, infoH, BG_3)
  border(page, colR, y - infoH, halfW, infoH)

  const infoRows: [string, string][] = [
    ["Proforma Invoice Nº", invoiceNum],
    ["Data de Emissão",     new Date(d.criadaEm).toLocaleDateString("pt-BR")],
    ["Validade da Proposta","7 dias"],
  ]
  let ry = y - 16
  for (const [label, val] of infoRows) {
    txt(page, bold, `${label}:`, colR + 10, ry, 7.5, TX_DIM)
    txt(page, bold, val, colR + 10, ry - 13, 9.5, TX)
    ry -= 30
  }

  y -= infoH + 18

  // ── TABELA DE PRODUTOS ────────────────────────────────────────────────────
  function rowHeight(item: ProposalItemData): number {
    let h = 28 // nome + margem
    if (item.ficha.hsCode) h += 11
    if ((item.coresEscolhidas ?? []).length > 0) h += 12
    if (item.observacoes) h += 12
    return Math.max(h, 44)
  }
  ;({ page, y } = ensure(doc, page, y, 28 + d.itens.reduce((s, it) => s + rowHeight(it), 0)))
  sectionTitle(page, bold, "DETALHES DOS PRODUTOS", y); y -= 4

  const tableW = PW - MX * 2
  // 6 colunas: Item | Descrição | MOQ | Containers | Preço Un. | Total
  const cW = [28, tableW - 28 - 58 - 52 - 82 - 82, 58, 52, 82, 82]
  const cX = cW.reduce<number[]>((acc, w, i) => { acc.push(i === 0 ? MX : acc[i - 1] + cW[i - 1]); return acc }, [])
  const headers = ["Item", "Descrição do Produto", "MOQ", "Containers", "Preço Un. (USD)", "Total (USD)"]

  fill(page, MX, y - 22, tableW, 22, LIME)
  for (let i = 0; i < headers.length; i++) {
    const align = i >= 2
    const tw = bold.widthOfTextAtSize(headers[i], 7)
    const tx = align ? cX[i] + cW[i] - tw - 5 : cX[i] + 5
    txt(page, bold, headers[i], tx, y - 15, 7, BG)
  }
  y -= 22

  // Pré-carrega imagens dos produtos
  type EmbeddedImg = Awaited<ReturnType<typeof doc.embedPng>> | Awaited<ReturnType<typeof doc.embedJpg>>
  const prodImgs: (EmbeddedImg | null)[] = await Promise.all(d.itens.map(async (item) => {
    if (!item.imagemUrl) return null
    try {
      const r = await fetch(item.imagemUrl)
      if (!r.ok) return null
      const buf = new Uint8Array(await r.arrayBuffer())
      const ct = r.headers.get("content-type") ?? ""
      return ct.includes("png") ? await doc.embedPng(buf) : await doc.embedJpg(buf)
    } catch { return null }
  }))

  for (let idx = 0; idx < d.itens.length; idx++) {
    const item = d.itens[idx]
    const ROW_H = rowHeight(item)
    ;({ page, y } = ensure(doc, page, y, ROW_H))
    fill(page, MX, y - ROW_H, tableW, ROW_H, idx % 2 === 0 ? BG_3 : BG)
    border(page, MX, y - ROW_H, tableW, ROW_H)

    const moqNum     = parseMoq(item.ficha.moq)
    const containers = item.quantidade ?? 1
    const total      = moqNum * containers * (item.valorUnit ?? 0)
    const moqStr     = item.ficha.moq ?? "—"
    const rowVals = [
      String(idx + 1).padStart(2, "0"),
      item.produto,
      moqStr,
      String(containers),
      item.valorUnit != null ? `$ ${fmt(item.valorUnit)}` : "sob consulta",
      total > 0 ? `$ ${fmt(total)}` : "—",
    ]
    for (let i = 0; i < rowVals.length; i++) {
      const align = i >= 2
      const f = i === 1 ? bold : font
      const tw = f.widthOfTextAtSize(rowVals[i], 9)
      const tx = align ? cX[i] + cW[i] - tw - 6 : cX[i] + 6
      txt(page, f, rowVals[i], tx, y - 13, 9, TX)
    }
    // Foto do produto (coluna Item, abaixo do número)
    const pImg = prodImgs[idx]
    const IMG_SZ = 34
    if (pImg) {
      const ratio = pImg.width / pImg.height
      const iw = ratio >= 1 ? IMG_SZ : IMG_SZ * ratio
      const ih = ratio >= 1 ? IMG_SZ / ratio : IMG_SZ
      page.drawImage(pImg, { x: cX[0] + (cW[0] - iw) / 2, y: y - ROW_H + (ROW_H - ih) / 2, width: iw, height: ih })
    }
    // HS Code + cores + obs na coluna Descrição (empilhados abaixo do nome)
    let descLine2Y = y - 26
    if (item.ficha.hsCode) {
      txt(page, font, `HS Code: ${item.ficha.hsCode}`, cX[1] + 6, descLine2Y, 7, TX_DIM)
      descLine2Y -= 11
    }
    // Cores escolhidas (com regra 50/50 quando 2 cores)
    const cores = item.coresEscolhidas ?? []
    if (cores.length > 0) {
      const corHex: Record<string, [number, number, number]> = { Preto: [0.1,0.1,0.1], Branco: [0.95,0.95,0.95], Vermelho: [0.88,0.21,0.21], Verde: [0.18,0.62,0.31], Amarelo: [0.91,0.76,0.16] }
      let cx2 = cX[1] + 6
      if (cores.length === 2) {
        // 50/50: bolinha cor1 + "50% Cor1 · 50% Cor2" + bolinha cor2
        const [r1,g1,b1] = corHex[cores[0]] ?? [0.5,0.5,0.5]
        const [r2,g2,b2] = corHex[cores[1]] ?? [0.5,0.5,0.5]
        page.drawCircle({ x: cx2 + 4, y: descLine2Y - 1, size: 4, color: rgb(r1,g1,b1), borderColor: rgb(0.7,0.7,0.7), borderWidth: 0.5 })
        cx2 += 11
        const label50 = `50% ${cores[0]}  ·  50% ${cores[1]}`
        txt(page, font, label50, cx2, descLine2Y, 7, TX_DIM); cx2 += font.widthOfTextAtSize(label50, 7) + 6
        page.drawCircle({ x: cx2 + 4, y: descLine2Y - 1, size: 4, color: rgb(r2,g2,b2), borderColor: rgb(0.7,0.7,0.7), borderWidth: 0.5 })
      } else {
        // 1 cor apenas
        const [r1,g1,b1] = corHex[cores[0]] ?? [0.5,0.5,0.5]
        page.drawCircle({ x: cx2 + 4, y: descLine2Y - 1, size: 4, color: rgb(r1,g1,b1), borderColor: rgb(0.7,0.7,0.7), borderWidth: 0.5 })
        cx2 += 11
        txt(page, font, cores[0], cx2, descLine2Y, 7, TX_DIM)
      }
      descLine2Y -= 12
    }
    // Observação do item
    if (item.observacoes) {
      txt(page, font, `Obs: ${item.observacoes}`, cX[1] + 6, descLine2Y, 7, TX_DIM)
    }
    y -= ROW_H
  }
  y -= 12

  // ── RESUMO FINANCEIRO ─────────────────────────────────────────────────────
  ;({ page, y } = ensure(doc, page, y, 66))
  sectionTitle(page, bold, "RESUMO FINANCEIRO", y); y -= 4

  const subtotal = d.itens.reduce((s, i) => s + parseMoq(i.ficha.moq) * (i.quantidade ?? 1) * (i.valorUnit ?? 0), 0)
  const totalVal = subtotal
  const rW = 210
  const rX = PW - MX - rW

  fill(page, rX, y - 26, rW, 26, BG_2)
  border(page, rX, y - 26, rW, 26)
  txt(page, font, "Subtotal:", rX + 10, y - 17, 8.5, TX_INV)
  const subStr = `USD $ ${fmt(subtotal)}`
  txt(page, bold, subStr, rX + rW - bold.widthOfTextAtSize(subStr, 9) - 10, y - 17, 9, TX_INV)
  y -= 26

  fill(page, rX, y - 30, rW, 30, LIME)
  txt(page, bold, "TOTAL GERAL:", rX + 10, y - 19, 9, BG)
  const totStr = `USD $ ${fmt(totalVal)}`
  txt(page, bold, totStr, rX + rW - bold.widthOfTextAtSize(totStr, 12) - 10, y - 20, 12, BG)
  y -= 44

  // ── CONDIÇÕES COMERCIAIS ──────────────────────────────────────────────────
  const condRows: [string, string][] = [
    ["Porto de Origem",     d.portoOrigem  ?? "SHENZHEN"],
    ["Porto de Destino",    d.portoDestino ?? "SANTOS"],
    ["Incoterm",            `FOB ${d.portoOrigem ?? "SHENZHEN"}`],
    ["Data de Entrega",     d.dataEntrega  ?? "30 dias após confirmação"],
    ["Forma de Pagamento",  "20% Produção / 80% BL Date"],
    ["Prazo de Produção",   "30 dias"],
    ["Moeda",               `Dólar Americano (${d.moeda})`],
    ["País de Origem",      "China (Made in China)"],
  ]
  const condH = 16 + Math.ceil(condRows.length / 2) * 26 + 10
  ;({ page, y } = ensure(doc, page, y, condH + 20))
  sectionTitle(page, bold, "CONDIÇÕES COMERCIAIS", y); y -= 4

  fill(page, MX, y - condH, PW - MX * 2, condH, BG_3)
  border(page, MX, y - condH, PW - MX * 2, condH)

  const condColW = (PW - MX * 2) / 2 - 10
  let col = 0, crow = 0
  for (const [label, val] of condRows) {
    const cx = MX + 12 + col * (condColW + 20)
    const cy = y - 18 - crow * 26
    txt(page, bold, `${label}:`, cx, cy, 7.5, TX_DIM)
    txt(page, font, val,          cx, cy - 13, 9, TX)
    col++
    if (col === 2) { col = 0; crow++ }
  }
  y -= condH + 16

  // ── DADOS BANCÁRIOS ───────────────────────────────────────────────────────
  const bankLines = [
    ["Beneficiário",  "ANHUI LIGHT INDUSTRIES INTERNATIONAL CO., LTD."],
    ["Banco",         "BANK OF CHINA, HEFEI CHANGJIANG ROAD SUB-BRANCH, Anhui Branch"],
    ["SWIFT",         "BKCHCNBJ780"],
    ["Conta Nº",      "184201151797"],
  ]
  const bankH = 18 + bankLines.length * 17 + 8
  ;({ page, y } = ensure(doc, page, y, bankH + 20))
  sectionTitle(page, bold, "DADOS BANCÁRIOS — PAGAMENTO T/T", y); y -= 4

  fill(page, MX, y - bankH, PW - MX * 2, bankH, BG_3)
  border(page, MX, y - bankH, PW - MX * 2, bankH)
  let by = y - 16
  for (const [label, val] of bankLines) {
    txt(page, bold, `${label}:`, MX + 10, by, 7.5, TX_DIM)
    txt(page, font, val, MX + 90, by, 8.5, TX)
    by -= 17
  }
  y -= bankH + 16

  // ── TERMOS E CONDIÇÕES ────────────────────────────────────────────────────
  const termos = [
    "O pedido só será processado após recebimento do sinal de pagamento conforme forma acordada.",
    "Discrepâncias de quantidade devem ser reportadas em até 15 dias após chegada no porto de destino;",
    "   qualidade, em até 30 dias (laudo de inspeção emitido por vistoriador internacional).",
    "Seguro de carga a cargo do Comprador.",
    "Litígios resolvidos por negociação amigável ou, em caso de impasse, submetidos à arbitragem CIETAC (Pequim).",
    "O Vendedor não responde por atrasos decorrentes de força maior.",
  ]
  const termosH = 18 + termos.length * 14 + 6
  ;({ page, y } = ensure(doc, page, y, termosH + 20))
  sectionTitle(page, bold, "TERMOS E CONDIÇÕES", y); y -= 4

  fill(page, MX, y - termosH, PW - MX * 2, termosH, BG_3)
  border(page, MX, y - termosH, PW - MX * 2, termosH)
  let ty = y - 16
  let tnum = 0
  for (const t of termos) {
    const isSubline = t.startsWith("   ")
    if (!isSubline) { tnum++; txt(page, bold, `${tnum}.`, MX + 10, ty, 7.5, TX_DIM) }
    txt(page, font, t.trim(), MX + (isSubline ? 22 : 22), ty, 7.5, TX_DIM)
    ty -= 14
  }
  y -= termosH + 16

  // ── OBSERVAÇÕES IMPORTANTES ───────────────────────────────────────────────
  const obsStd = [
    "Esta Proforma Invoice não constitui uma fatura fiscal.",
    "Os valores podem sofrer alteração após o prazo de validade.",
    "O pedido será confirmado somente após o pagamento inicial.",
    "Venda diretamente da fábrica.",
  ]
  if (d.observacoes) obsStd.push(d.observacoes)

  const obsH = 18 + obsStd.length * 15
  ;({ page, y } = ensure(doc, page, y, obsH + 20))
  sectionTitle(page, bold, "OBSERVAÇÕES IMPORTANTES", y); y -= 16

  for (const obs of obsStd) {
    ;({ page, y } = ensure(doc, page, y, 16))
    txt(page, bold, "•",  MX,      y, 9, LIME)
    txt(page, font, obs,  MX + 12, y, 8.5, TX_DIM)
    y -= 15
  }
  y -= 14

  // ── ASSINATURA ────────────────────────────────────────────────────────────
  ;({ page, y } = ensure(doc, page, y, 50))
  const sigW = (PW - MX * 2 - 24) / 2
  page.drawLine({ start: { x: MX,              y: y - 24 }, end: { x: MX + sigW,             y: y - 24 }, thickness: 0.5, color: TX_DIM })
  txt(page, font, "Assinatura do Cliente",   MX,              y - 36, 7.5, TX_DIM)
  page.drawLine({ start: { x: MX + sigW + 24, y: y - 24 }, end: { x: PW - MX,                y: y - 24 }, thickness: 0.5, color: TX_DIM })
  txt(page, font, "Carimbo / Aprovação (GOV)", MX + sigW + 24, y - 36, 7.5, TX_DIM)

  drawFooter(page, font, PW)
  return doc.save()
}

// ── helpers ───────────────────────────────────────────────────────────────────

function fill(page: PDFPage, x: number, y: number, w: number, h: number, color: ReturnType<typeof rgb>) {
  page.drawRectangle({ x, y, width: w, height: h, color })
}

function border(page: PDFPage, x: number, y: number, w: number, h: number) {
  page.drawRectangle({ x, y, width: w, height: h, borderColor: LINE, borderWidth: 0.4, color: undefined })
}

function txt(page: PDFPage, f: PDFFont, text: string, x: number, y: number, size: number, color: ReturnType<typeof rgb>) {
  page.drawText(text, { x, y, size, font: f, color })
}

function txtClip(page: PDFPage, f: PDFFont, text: string, x: number, y: number, size: number, color: ReturnType<typeof rgb>, maxW: number) {
  let s = size
  while (s > 8 && f.widthOfTextAtSize(text, s) > maxW) s -= 0.5
  page.drawText(text, { x, y, size: s, font: f, color })
}

function sectionTitle(page: PDFPage, bold: PDFFont, title: string, y: number) {
  page.drawText(title, { x: MX, y, size: 8.5, font: bold, color: LIME })
}

function fmt(n: number): string {
  return n.toLocaleString("pt-BR", { minimumFractionDigits: 2, maximumFractionDigits: 2 })
}

function parseMoq(moq: string | null): number {
  if (!moq) return 0
  const n = parseFloat(moq.replace(/[^\d.]/g, ""))
  return isNaN(n) ? 0 : n
}

function drawFooter(page: PDFPage, font: PDFFont, width: number) {
  page.drawLine({ start: { x: MX, y: FOOTER_Y }, end: { x: width - MX, y: FOOTER_Y }, thickness: 0.5, color: LINE })
  txt(page, font, "Cotação sujeita à análise cadastral e financeira. Condições finais confirmadas pela equipe TradeK.", MX, FOOTER_Y - 12, 7, TX_DIM)
  txt(page, font, "TradeK · Hub de negócios China–Brasil · www.tradek.com.br", MX, FOOTER_Y - 23, 7, TX_DIM)
}
